const item = $input.first()?.json ?? {};
const body = item.body ?? {};
const query = item.query ?? {};
const projectDir = body.project_dir ?? query.project_dir ?? 'D:\\workspace\\trend-radar';
const launcher = body.launcher ?? query.launcher ?? 'python -m trend_radar';
const outputDir = body.output_dir ?? query.output_dir ?? '';
const configPath = body.config_path ?? query.config_path ?? '';
const escapeForCmd = (value) => String(value).replace(/"/g, '""');
let command = `cd /d "${escapeForCmd(projectDir)}" && ${launcher}`;
if (configPath) command += ` --config "${escapeForCmd(configPath)}"`;
command += ' digest today';
if (outputDir) command += ` --output-dir "${escapeForCmd(outputDir)}"`;
command += ' --json';
return [{
  json: {
    project_dir: projectDir,
    launcher,
    output_dir: outputDir || null,
    config_path: configPath || null,
    command,
  },
}];

const item = $input.first()?.json ?? {};
const stdout = item.stdout ?? '';
const stderr = item.stderr ?? '';
const exitCode = item.exitCode ?? 0;
let payload = {};
try {
  payload = stdout ? JSON.parse(stdout) : {};
} catch (error) {
  payload = {
    path: null,
    content: stdout,
    parse_error: error.message,
  };
}
const preview = payload.content ? payload.content.split('\n').slice(0, 12).join('\n') : '';
return [{
  json: {
    ...payload,
    preview,
    exit_code: exitCode,
    stderr,
    raw_stdout: stdout,
  },
}];
